sql:
SELECT fund_id, COUNT(class_id) AS num_classes
FROM fund_classes
GROUP BY fund_id;

SELECT fund_name, fund_type
FROM funds
WHERE fund_id = 20001;

external_knowledge:
- 'fund classes' refer to different types or versions of mutual funds offered by a fund manager;
- 'average values of shares' correspond to the average Net Asset Value (NAV) per share;
- 'over time, roughly expressed in months' means the data is aggregated by month (year-month format).

sql:
SELECT SUM(holding_value) AS total_holding_value
FROM fund_holdings
WHERE holding_value > (SELECT AVG(holding_value) FROM fund_holdings WHERE sector = 'Technology');
